import requests; from requests.auth import HTTPBasicAuth
HEADERS = {"Accept": "application/yang-data+json", "Content-Type": "application/yang-data+json"}
AUTH = HTTPBasicAuth("admin", "lab-password")
VLAN_URL = "https://192.168.1.10/restconf/data/Cisco-IOS-XE-native:native/vlan"
def patch_config(url, payload, auth):
    r = requests.patch(url, json=payload, headers=HEADERS, auth=auth, verify=False)
    r.raise_for_status()
    return r
PAYLOAD = {"Cisco-IOS-XE-native:vlan-list": [{"id": 100, "name": "DATA_VLAN"}]}
try:
    patch_config(VLAN_URL, PAYLOAD, AUTH)
except requests.HTTPError as e:
    print(f"HTTP error: {e.response.status_code}")
    print(e.response.text[:500])

