from netmiko import ConnectHandler

BRANCH_HOSTS = ["192.168.1.10", "192.168.1.11"]
DEVICE = {"device_type": "cisco_ios", "username": "admin", "password": "lab-password"}

def run_show(host, command):
    conn = ConnectHandler(host=host, **DEVICE)
    print(conn.send_command(command))
    conn.disconnect()

for host in BRANCH_HOSTS:
    print(f"--- {host} show vlan brief ---")
    run_show(host, "show vlan brief")
